// Validate Data Completeness from Healthcare Systems
// Checks EHR, Nursing, Pharmacy, and Case Management data

const items = $input.all();
const validationResults = [];

for (const item of items) {
  const data = item.json;
  const missingFields = [];
  let isValid = true;

  // Validate EHR Patient Data
  const ehrRequired = ['patientId', 'firstName', 'lastName', 'dateOfBirth', 'medicalRecordNumber'];
  if (!data.ehr) {
    missingFields.push('ehr (entire object)');
    isValid = false;
  } else {
    for (const field of ehrRequired) {
      if (!data.ehr[field]) {
        missingFields.push(`ehr.${field}`);
        isValid = false;
      }
    }
  }

  // Validate Nursing Status Data
  const nursingRequired = ['assignedNurse', 'vitalSigns', 'lastAssessment', 'careLevel'];
  if (!data.nursing) {
    missingFields.push('nursing (entire object)');
    isValid = false;
  } else {
    for (const field of nursingRequired) {
      if (!data.nursing[field]) {
        missingFields.push(`nursing.${field}`);
        isValid = false;
      }
    }
  }

  // Validate Pharmacy Readiness Data
  const pharmacyRequired = ['medicationList', 'allergies', 'pharmacistReview', 'readyForDispense'];
  if (!data.pharmacy) {
    missingFields.push('pharmacy (entire object)');
    isValid = false;
  } else {
    for (const field of pharmacyRequired) {
      if (!data.pharmacy[field]) {
        missingFields.push(`pharmacy.${field}`);
        isValid = false;
      }
    }
  }

  // Validate Case Management Data
  const caseManagementRequired = ['caseManager', 'dischargeStatus', 'followUpPlan', 'insuranceVerified'];
  if (!data.caseManagement) {
    missingFields.push('caseManagement (entire object)');
    isValid = false;
  } else {
    for (const field of caseManagementRequired) {
      if (!data.caseManagement[field]) {
        missingFields.push(`caseManagement.${field}`);
        isValid = false;
      }
    }
  }

  // Build validation result
  validationResults.push({
    json: {
      ...data,
      validation: {
        isValid: isValid,
        missingFields: missingFields,
        validatedAt: new Date().toISOString(),
        totalMissingFields: missingFields.length
      }
    }
  });
}

return validationResults;

